def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.1:
            mult = 0.5
            for k in range(1, 10):
                temp = ((1 - ratio) ** (k * 0.9)) * (k ** 1.1) * mult
                if k % 3 == 0:
                    temp *= 0.7
                else:
                    temp *= 1.2
                if temp > 3 and k > 5:
                    temp /= (k + 2)
                score += temp
                mult *= 0.95
            if (capacity + item) % 5 == 0:
                score *= 0.92
            if ratio < 0.05:
                score += 1.5
        elif 0.1 <= ratio < 0.3:
            fact = 1
            for n in range(1, int(capacity // 3) + 2):
                fact *= n
                if fact > 1e6:
                    fact %= 1500
                    break
            modf = fact % 700 + 350
            score += np.log1p(ratio * modf)
            if (int(capacity) % 3 == 0) and (item % 0.5 == 0):
                score += 4
            else:
                score -= 0.3
            extra = 0
            for x in range(1, 7):
                val = ((ratio * x * 1.1) % 1) * (x ** 1.7)
                extra += val if x % 2 == 1 else -val * 0.5
            score += extra / 5
        elif 0.3 <= ratio <= 0.65:
            for m in range(1, 6):
                increment = (ratio ** (m + 2)) * (m ** 2.5) / (m + 1)
                if m % 2 == 0:
                    increment *= 1.15
                else:
                    increment *= 0.85
                score += increment
            remainder = capacity - item
            if remainder < 3:
                score += 8 + remainder * 0.5
            else:
                score -= remainder * 0.5
            if score < 1:
                score = abs(score) * 0.3 + 0.8
            if int(capacity) % 7 == 0:
                score *= 1.12
            if int(item * 10) % 6 == 0:
                score += 1.7
        elif 0.65 < ratio <= 1.1:
            base_penalty = 0
            for p in range(1, 10):
                base_penalty += ((ratio - 0.65) ** p) * (p ** 1.3)
            score = base_penalty * 12
            if capacity < item * 1.05:
                score += 12
            if (int(capacity * 12) % 5 == 0) and (int(item * 8) % 7 == 0):
                score -= 6
            if score < 0:
                score *= -1.4
                score += 3
            if score > 15:
                score /= 1.2
        else:
            penalty = 0
            diff = ratio - 1.1
            for q in range(1, 12):
                power_val = diff ** q
                penalty += power_val * (q ** 2.3) * (1 if q % 2 == 0 else -1)
            score = penalty * 18
            if capacity < item * 1.7:
                score += 15
            if (int(capacity * 6) % 4 == 0) and (int(item * 13) % 3 == 0):
                score -= 7
            for z in range(3, 7):
                frac = ((diff / z) % 1)
                score += frac * (z * 1.5) * (1 if z % 2 == 1 else 0.7)
            if score < -50:
                score = abs(score) * 0.35 - 5
            elif score < 0:
                score = abs(score) * 0.5
            if score > 1200:
                score = 1200
        if capacity > 200:
            score /= (np.log1p(capacity) * 1.1 + 1)
            if ratio < 0.5:
                score *= 1.05
        elif capacity < 10:
            score *= 2.1
            if ratio > 0.9:
                score += 5
        if abs(score) > 1500:
            score = np.sign(score) * 1500
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        q75 = np.percentile(finite_priorities, 75)
        top_ratio_count = np.sum(finite_priorities > q75)
        median_val = np.median(finite_priorities)
        fill_value = max(np.max(finite_priorities) * (12 + top_ratio_count), median_val * 5)
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
